import android.widget.Toast
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import androidx.core.content.ContextCompat
import androidx.core.content.FileProvider
import com.example.yourapp.databinding.ActivityMainBinding
import java.io.File
import java.io.IOException
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

class MainActivity : AppCompatActivity() {

    private lateinit var binding: ActivityMainBinding
    private lateinit var webView: WebView
    private var filePathCallback: ValueCallback<Array<Uri>>? = null
    private var cameraPhotoPath: String? = null

    // Permission request launcher for camera
    private val requestCameraPermissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted: Boolean ->
        if (isGranted) {
            Toast.makeText(this, "Camera permission granted!", Toast.LENGTH_SHORT).show()
            // If you need to do something immediately after permission is granted, do it here
            // e.g., restart a previous camera interaction
        } else {
            Toast.makeText(this, "Camera permission denied.", Toast.LENGTH_SHORT).show()
        }
    }

    // Activity result launcher for file chooser (gallery/camera)
    private val fileChooserLauncher = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        if (filePathCallback == null) return@registerForActivityResult

        var results: Array<Uri>? = null

        if (result.resultCode == Activity.RESULT_OK) {
            if (result.data == null) {
                // If there is no data, then we may have taken a photo
                cameraPhotoPath?.let {
                    val contentUri = FileProvider.getUriForFile(
                        this,
                        "${applicationContext.packageName}.fileprovider",
                        File(it)
                    )
                    results = arrayOf(contentUri)
                }
            } else {
                val dataString = result.data?.dataString
                if (dataString != null) {
                    results = arrayOf(Uri.parse(dataString))
                }
            }
        }
        filePathCallback?.onReceiveValue(results)
        filePathCallback = null
        cameraPhotoPath = null
    }

    @SuppressLint("SetJavaScriptEnabled")
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        binding = ActivityMainBinding.inflate(layoutInflater)
        setContentView(binding.root)

        webView = binding.webView

        // Configure WebView settings
        webView.settings.apply {
            javaScriptEnabled = true // Enable JavaScript
            domStorageEnabled = true // Enable HTML5 DOM storage
            databaseEnabled = true // Enable HTML5 database storage
            allowFileAccess = true // Allow WebView to access local files
            allowContentAccess = true // Allow WebView to access content URIs
            loadsImagesAutomatically = true // Load images automatically
            mixedContentMode = WebSettings.MIXED_CONTENT_ALWAYS_ALLOW // Allow HTTPS pages to load HTTP content
            loadWithOverviewMode = true // Load page in overview mode (zoomed out)
            useWideViewPort = true // Use wide viewport for responsive design
            mediaPlaybackRequiresUserGesture = false // Allow autoplay of media
            javaScriptCanOpenWindowsAutomatically = true // Allow JavaScript to open new windows
        }

        // Set WebViewClient to handle page navigation within the WebView
        webView.webViewClient = object : WebViewClient() {
            override fun onPageFinished(view: WebView?, url: String?) {
                super.onPageFinished(view, url)
                // Optional: You can inject JS here after the page loads, e.g., to confirm bridge readiness
                view?.evaluateJavascript("console.log('WebView bridge ready!');", null)
            }
        }

        // Set WebChromeClient to handle JavaScript dialogs, favicons, titles, and file uploads
        webView.webChromeClient = object : WebChromeClient() {
            override fun onConsoleMessage(consoleMessage: ConsoleMessage?): Boolean {
                consoleMessage?.let {
                    // Log JavaScript console messages to Logcat
                    android.util.Log.d("WebViewConsole", "${it.message()} -- From line ${it.lineNumber()} of ${it.sourceId()}")
                }
                return super.onConsoleMessage(consoleMessage)
            }

            override fun onGeolocationPermissionsShowPrompt(
                origin: String?,
                callback: GeolocationPermissions.Callback?
            ) {
                // Grant geolocation permission for the origin
                callback?.invoke(origin, true, false)
            }

            override fun onPermissionRequest(request: PermissionRequest?) {
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) {
                    val resources = request?.resources
                    if (resources != null) {
                        if (resources.contains(PermissionRequest.RESOURCE_VIDEO_CAPTURE) ||
                            resources.contains(PermissionRequest.RESOURCE_AUDIO_CAPTURE)) {
                            // Check app-level permissions before granting WebView permission
                            if (ContextCompat.checkSelfPermission(this@MainActivity, Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED) {
                                request.grant(resources)
                            } else {
                                // Request permission using the ActivityResultLauncher
                                requestCameraPermissionLauncher.launch(Manifest.permission.CAMERA)
                                // Deny the WebView request for now; it might be re-requested after permission is granted
                                request.deny()
                            }
                        } else {
                            super.onPermissionRequest(request)
                        }
                    }
                } else {
                    super.onPermissionRequest(request)
                }
            }


            // For Android 5.0+
            override fun onShowFileChooser(
                webView: WebView?,
                filePathCallback: ValueCallback<Array<Uri>>?,
                fileChooserParams: FileChooserParams?
            ): Boolean {
                this@MainActivity.filePathCallback = filePathCallback

                // Determine whether to open camera, gallery, or both
                val intentArray: Array<Intent?>
                if (fileChooserParams?.isCaptureEnabled == true) {
                    intentArray = arrayOf(createCameraIntent())
                } else {
                    intentArray = arrayOf()
                }

                val contentSelectionIntent = Intent(Intent.ACTION_GET_CONTENT).apply {
                    addCategory(Intent.CATEGORY_OPENABLE)
                    type = if (fileChooserParams?.acceptTypes?.contains("video/") == true) "video/*" else "image/*"
                }

                val chooserIntent = Intent(Intent.ACTION_CHOOSER).apply {
                    putExtra(Intent.EXTRA_INTENT, contentSelectionIntent)
                    putExtra(Intent.EXTRA_TITLE, "Image Chooser")
                    putExtra(Intent.EXTRA_INITIAL_INTENTS, intentArray)
                }

                fileChooserLauncher.launch(chooserIntent)
                return true
            }
        }

        // Add the JavaScript interface
        webView.addJavascriptInterface(
            JavaScriptBridge(this, applicationContext),
            "Android" // The name of the object in JavaScript (e.g., `window.Android.callCamera()`)
        )

        // Load your mobile web app URL
        // Example: If your web app is hosted locally or a public URL
        webView.loadUrl("file:///android_asset/index.html")
        // webView.loadUrl("https://your.mobile.webapp.com")
    }

    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            super.onBackPressed()
        }
    }

    @Throws(IOException::class)
    private fun createImageFile(): File {
        // Create an image file name
        val timeStamp: String = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(Date())
        val storageDir: File? = getExternalFilesDir(Environment.DIRECTORY_PICTURES)
        return File.createTempFile(
            "JPEG_${timeStamp}_", /* prefix */
            ".jpg", /* suffix */
            storageDir /* directory */
        ).apply {
            // Save a file: path for use with ACTION_VIEW intents
            cameraPhotoPath = absolutePath
        }
    }

    private fun createCameraIntent(): Intent {
        val takePictureIntent = Intent(MediaStore.ACTION_IMAGE_CAPTURE)
        // Ensure that there's a camera activity to handle the intent
        if (takePictureIntent.resolveActivity(packageManager) != null) {
            // Create the File where the photo should go
            var photoFile: File? = null
            try {
                photoFile = createImageFile()
            } catch (ex: IOException) {
                // Error occurred while creating the File
                android.util.Log.e("WebView", "Error creating image file", ex)
            }
            // Continue only if the File was successfully created
            photoFile?.also {
                val photoURI: Uri = FileProvider.getUriForFile(
                    this,
                    "${applicationContext.packageName}.fileprovider",
                    it
                )
                takePictureIntent.putExtra(MediaStore.EXTRA_OUTPUT, photoURI)
            }
        }
        return takePictureIntent
    }


